// Get current notifications
  const notifications = [...variables['5acccfc8-5200-4669-b034-c4e0e64c3a4d']];

  // Find and update the specific notification
  const updatedNotifications = notifications.map(notification => {
    if (notification.id === context.parameters['notificationId']) {
      return {
        ...notification,
        isRead: true
      };
    }
    return notification;
  });

  // Update notifications variable
  variables['5acccfc8-5200-4669-b034-c4e0e64c3a4d'] = updatedNotifications;

  return true;

